def editar_minuta_dashboard(request, minuta_id):
    # busca a minuta especificada ou retorna 404 se não existir
    minuta = get_object_or_404(MinutaGerada, id=minuta_id)
    capitulos_padrao = BlocoPadrao.objects.filter(bloco_pai__isnull=True).order_by('ordem_padrao')

    # busca os blocos da minuta, ordenados pela ordem definida
    blocos_da_minuta = minuta.blocos.order_by('ordem')

    campos_variaveis = []
    
    campos_ignorados = ['id', 'nome_interno', 'criado_em', 'atualizado_em'] 
    
    # Varre todos os campos que existem no seu modelo MinutaGerada
    for campo in minuta._meta.fields:
        if campo.name not in campos_ignorados:
            valor = getattr(minuta, campo.name)
            campos_variaveis.append({
                'name': campo.name,
                # O Django já transforma 'prazo_arrendamento' em 'Prazo arrendamento' automaticamente
                'label': campo.verbose_name.title(), 
                'valor': valor if valor is not None else ''
            })

    context = {
        'minuta': minuta,
        'capitulos_padrao': capitulos_padrao,
        'blocos_da_minuta': blocos_da_minuta,
        'campos_variaveis': campos_variaveis, # Passamos a nossa lista inteligente
    }

    return render(request, 'gerador_avancado/editar_minuta.html', context)

def adicionar_bloco_ajax(request, minuta_id, bloco_padrao_id):
    if request.method == 'POST':
        minuta = get_object_or_404(MinutaGerada, id=minuta_id)
        bloco_origem = get_object_or_404(BlocoPadrao, id=bloco_padrao_id)

        # impedir duplicidade
        if BlocoDaMinuta.objects.filter(minuta=minuta, bloco_origem=bloco_origem).exists():
            return JsonResponse({
                'status': 'erro', 
                'mensagem': 'Esta seção já foi adicionada a este edital!'
            }, status=400)
        
        # Pega a última ordem do documento
        ultima_ordem = minuta.blocos.aggregate(Max('ordem'))['ordem__max'] or 0
        ordem_atual = ultima_ordem + 10
        
        novo_bloco = BlocoDaMinuta.objects.create(
            minuta=minuta,
            bloco_origem=bloco_origem,
            tipo=bloco_origem.tipo,
            titulo=bloco_origem.titulo,
            conteudo_editado=bloco_origem.conteudo,
            ordem=ordem_atual
        )
        
        filhos = BlocoPadrao.objects.filter(bloco_pai=bloco_origem).order_by('ordem_padrao')
        
        for filho in filhos:
            ordem_atual += 10 
            
            BlocoDaMinuta.objects.create(
                minuta=minuta,
                bloco_origem=filho,
                tipo=filho.tipo,
                titulo=filho.titulo,
                conteudo_editado=filho.conteudo,
                bloco_pai=novo_bloco,
                ordem=ordem_atual
            )
            
        return JsonResponse({'status': 'sucesso'})
    
    return JsonResponse({'status': 'erro', 'mensagem': 'Método inválido'}, status=400)

def remover_bloco_ajax(request, bloco_minuta_id):
    if request.method == 'POST':
        bloco = get_object_or_404(BlocoDaMinuta, id=bloco_minuta_id)
        bloco.delete()
        return JsonResponse({'status': 'sucesso'})
    
    return JsonResponse({'status': 'erro', 'mensagem': 'Método inválido'}, status=400)

@csrf_exempt # Para facilitar o salvamento via JS
def salvar_conteudo_bloco_ajax(request, bloco_id):
    if request.method == 'POST':
        data = json.loads(request.body)
        novo_conteudo = data.get('conteudo')
        
        bloco = get_object_or_404(BlocoDaMinuta, id=bloco_id)
        bloco.conteudo_editado = novo_conteudo
        bloco.save()
        
        return JsonResponse({'status': 'sucesso'})
    return JsonResponse({'status': 'erro'}, status=400)

# reordenação dos blocos via drag-and-drop
@csrf_exempt
def reordenar_blocos_ajax(request, minuta_id):
    if request.method == 'POST':
        try:
            data = json.loads(request.body)
            itens = data.get('itens', [])
            
            # Garantimos que os blocos pertencem à minuta informada
            for item in itens:
                BlocoDaMinuta.objects.filter(
                    id=item['id'], 
                    minuta_id=minuta_id
                ).update(ordem=item['ordem'])
            
            return JsonResponse({'status': 'sucesso'})
        except Exception as e:
            return JsonResponse({'status': 'erro', 'mensagem': str(e)}, status=500)
    return JsonResponse({'status': 'erro'}, status=400)

# pré-visualização da minuta (página de visualização sem edição)
def preview_minuta(request, minuta_id):
    minuta = get_object_or_404(MinutaGerada, id=minuta_id)
    blocos = minuta.blocos.all().order_by('ordem')
    capitulos_padrao = BlocoPadrao.objects.filter(bloco_pai__isnull=True).order_by('ordem_padrao')

    # Transforma todos os campos da Minuta (porto, prazo, etc) num Dicionário do Django
    dados_variaveis = model_to_dict(minuta)
    contexto_dinamico = Context(dados_variaveis)

    # Varre cada bloco do documento para fazer a troca
    for bloco in blocos:
        if bloco.conteudo_editado:
            template_texto = Template(bloco.conteudo_editado)
            # Ele procura todas as tags {{ }} no texto e troca pelos valores do dicionário
            bloco.texto_final_renderizado = template_texto.render(contexto_dinamico)

    return render(request, 'gerador_avancado/preview_minuta.html', {
        'minuta': minuta,
        'blocos': blocos,
        'capitulos_padrao': capitulos_padrao,
    })

def gerar_pdf_minuta(request, minuta_id):
    minuta = get_object_or_404(MinutaGerada, id=minuta_id)
    blocos = minuta.blocos.all().order_by('ordem')
    capitulos_padrao = BlocoPadrao.objects.filter(bloco_pai__isnull=True).order_by('ordem_padrao')

    dados_variaveis = model_to_dict(minuta)
    contexto_dinamico = Context(dados_variaveis)

    for bloco in blocos:
        if bloco.conteudo_editado:
            template_texto = Template(bloco.conteudo_editado)
            bloco.texto_final_renderizado = template_texto.render(contexto_dinamico)

    # Renderiza o HTML
    html_string = render_to_string('gerador_avancado/preview_minuta.html', {
        'minuta': minuta,
        'blocos': blocos,
        'capitulos_padrao': capitulos_padrao,
    }, request=request)

    antaq_logo = "data:image/png;base64,"
    gov_logo = "data:image/png;base64,"
    
    # Usa o Playwright para gerar o PDF perfeitamente
    try:
        with sync_playwright() as p:
            browser = p.chromium.launch()
            page = browser.new_page()
            
            page.set_content(html_string, wait_until="domcontentloaded", timeout=30000)
            # cabeçalho de todas as páginas
            cabecalho_html = f"""
            <table style="width: 100%; margin: 5mm 25mm 0 25mm; padding: 0; border-collapse: collapse; font-family: Arial, sans-serif;">
                <tr>
                    <td style="text-align: center; vertical-align: middle;">
                        
                        <img src="{antaq_logo}" style="height: 80px; margin-right: 5px;" alt="Logo 1" />
                        
                        <img src="{gov_logo}" style="height: 85px; margin-left: 5px;" alt="Logo 2" />
                        
                    </td>
                </tr>
            </table>
            """
            
            rodape_html = """
            <div style="width: 100%; text-align: center; font-size: 10px; font-family: Arial, sans-serif;">
                <span class="pageNumber"></span>
            </div>
            """

            pdf_bytes = page.pdf(
                format="A4",
                print_background=True,
                margin={"top": "35mm", "bottom": "25mm", "left": "25mm", "right": "25mm"},
                display_header_footer=True,
                header_template=cabecalho_html,
                footer_template=rodape_html
            )
            browser.close()
            
    except Exception as e:
        # Se algo falhar, ele devolve o erro na tela para podermos investigar, em vez de travar
        return HttpResponse(f"<h1>Erro ao gerar PDF</h1><p>{str(e)}</p>", status=500)

    # Se der tudo certo, faz o download do arquivo
    response = HttpResponse(pdf_bytes, content_type='application/pdf')
    nome_arquivo = f"Minuta_Edital_{minuta.leilao}_Porto_{minuta.porto}.pdf"

    acao = request.GET.get('acao', 'baixar')

    if acao == 'ver':
        # "inline" abre o PDF nativo dentro da aba do navegador do usuário
        response['Content-Disposition'] = f'inline; filename="{nome_arquivo}"'
    else:
        # "attachment" força o download do arquivo para o computador
        response['Content-Disposition'] = f'attachment; filename="{nome_arquivo}"'

    return response

# No final do seu arquivo views.py
@csrf_exempt
def criar_secao_ajax(request):
    if request.method == 'POST':
        try:
            data = json.loads(request.body)
            titulo = data.get('titulo')
            capitulo_id = data.get('capitulo_id')
            
            if not titulo or not capitulo_id:
                return JsonResponse({'status': 'erro', 'mensagem': 'Título e Capítulo são obrigatórios.'})

            # Busca o capítulo pai
            capitulo_pai = get_object_or_404(BlocoPadrao, id=capitulo_id)
            
            # Descobre qual é a ordem correta para colocar a nova seção no final do capítulo
            ultimo_filho = capitulo_pai.sub_blocos.order_by('-ordem_padrao').first()
            nova_ordem = (ultimo_filho.ordem_padrao + 10) if ultimo_filho else (capitulo_pai.ordem_padrao + 10)
            
            # Cria a nova seção no banco 
            BlocoPadrao.objects.create(
                tipo=TipoBloco.SECAO, # garante que será uma Seção (SE)
                titulo=titulo,
                bloco_pai=capitulo_pai,
                ordem_padrao=nova_ordem
            )
            
            return JsonResponse({'status': 'sucesso'})
        except Exception as e:
            return JsonResponse({'status': 'erro', 'mensagem': str(e)}, status=500)
    return JsonResponse({'status': 'erro'}, status=400)

# Criar textos 
@csrf_exempt
def criar_texto_ajax(request, minuta_id):
    if request.method == 'POST':
        try:
            data = json.loads(request.body)
            capitulo_id = data.get('capitulo_id')
            bloco_referencia_id = data.get('bloco_referencia_id') 
            
            minuta = get_object_or_404(MinutaGerada, id=minuta_id)
            capitulo = get_object_or_404(BlocoPadrao, id=capitulo_id)
            
            # ficar logo abaixo do bloco de referência
            if bloco_referencia_id:
                bloco_ref = get_object_or_404(BlocoDaMinuta, id=bloco_referencia_id)
                nova_ordem = bloco_ref.ordem + 1 
            else:
                nova_ordem = 1 # Fallback de segurança
            
            # Cria a referência na Biblioteca Padrão com a ordem calculada
            novo_texto_padrao = BlocoPadrao.objects.create(
                tipo='TX',
                titulo="",
                conteudo="<p>Novo texto (clique para editar)</p>",
                bloco_pai=capitulo,
                ordem_padrao=nova_ordem
            )
            
            # Adiciona o texto na Minuta atual, colado no Apêndice
            BlocoDaMinuta.objects.create(
                minuta=minuta,
                bloco_origem=novo_texto_padrao,
                tipo='TX',
                titulo="",
                conteudo_editado="<p>Novo texto (clique para editar)</p>",
                ordem=nova_ordem
            )
            
            return JsonResponse({'status': 'sucesso'})
        except Exception as e:
            return JsonResponse({'status': 'erro', 'mensagem': str(e)}, status=500)
    return JsonResponse({'status': 'erro'}, status=400)

# Criar Cláusulas 
@csrf_exempt
def criar_clausula_ajax(request, minuta_id):
    if request.method == 'POST':
        try:
            data = json.loads(request.body)
            capitulo_id = data.get('capitulo_id')
            bloco_referencia_id = data.get('bloco_referencia_id') # Recebe o ID do bloco atual
            
            minuta = get_object_or_404(MinutaGerada, id=minuta_id)
            capitulo = get_object_or_404(BlocoPadrao, id=capitulo_id)
            
            # Ficar logo abaixo de onde clicou
            if bloco_referencia_id:
                bloco_ref = get_object_or_404(BlocoDaMinuta, id=bloco_referencia_id)
                nova_ordem = bloco_ref.ordem + 1
            else:
                ultimo_bloco = minuta.blocos.order_by('-ordem').first()
                nova_ordem = (ultimo_bloco.ordem + 10) if ultimo_bloco else 10
                
            nova_clausula_padrao = BlocoPadrao.objects.create(
                tipo='CL',
                titulo="",
                conteudo="<p>Nova cláusula (clique para editar)</p>",
                bloco_pai=capitulo,
                ordem_padrao=nova_ordem
            )
            
            BlocoDaMinuta.objects.create(
                minuta=minuta,
                bloco_origem=nova_clausula_padrao,
                tipo='CL',
                titulo="",
                conteudo_editado="<p>Nova cláusula (clique para editar)</p>",
                ordem=nova_ordem
            )
            
            return JsonResponse({'status': 'sucesso'})
        except Exception as e:
            return JsonResponse({'status': 'erro', 'mensagem': str(e)}, status=500)
    return JsonResponse({'status': 'erro'}, status=400)


